   public IEnumerable<SparePartEntity> FindMultiById(IEnumerable<string> sparePartIds)
   {
       var descriptor = new SearchDescriptor<SparePartEntity>();
       foreach (var id in sparePartIds)
       {
           var searchRequest = new SearchRequest<SparePartEntity>(Indices.All)
           {
               Query = new TermQuery { Field = Infer.Field<SparePartEntity>(ff => ff.SparePartId), Value = id }
           };

           descriptor.Requests = descriptor.Requests ?? new List<ISearchRequest>();
           descriptor.Requests.Add(searchRequest);
       }

       var multiSearchResponse = _client.MultiSearch(descriptor);

       var queryResponses = multiSearchResponse.Responses;
       foreach (var sparePartId in sparePartIds)
       {
           var source = multiSearchResponse.GetResponse<SparePartEntity>(sparePartId);
           if (source.Documents == null || !source.Documents.Any())
           {
               //_logger.Warn("did not found spare part for attribute: " + sparePartId);
               //_logger.Warn(JsonConvert.SerializeObject(source, Formatting.Indented));

               if (source.ApiCall != null)
               {
                   _logger.Error("sent request was: " + JsonConvert.SerializeObject(source.ApiCall));
               }
           }
       }

       foreach (var source in queryResponses)
       {
           if (source.Shards != null && source.Shards.Failed > 0)
           {
               _logger.Error("shards failed while getting attributes");
           }
           if (source.ApiCall != null && !source.ApiCall.Success)
           {
               _logger.Error("error while getting documents: " + JsonConvert.SerializeObject(source.OriginalException));
           }
       }
       return queryResponses.SelectMany(r => r.Documents.Values);
   }
